<script setup lang="ts">
import {nextTick,ref} from 'vue';const props=withDefaults(defineProps<{label?:string;side?:'top'|'right'|'bottom'|'left';align?:'start'|'center'|'end';sideOffset?:number;alignOffset?:number;closeOnOutside?:boolean;closeOnEscape?:boolean}>(),{label:'Actions',side:'bottom',align:'center',sideOffset:8,alignOffset:0,closeOnOutside:true,closeOnEscape:true});const shown=ref(true),trigger=ref<HTMLButtonElement>(),panel=ref<HTMLElement>();async function toggle(){shown.value=!shown.value;if(shown.value){await nextTick();panel.value?.focus()}}function key(e:KeyboardEvent){if(e.key==='Escape'&&props.closeOnEscape){shown.value=false;trigger.value?.focus()}}function blur(e:FocusEvent){if(props.closeOnOutside&&!e.currentTarget?.contains(e.relatedTarget as Node))shown.value=false}
</script>
<template><main class="popover-shell" @keydown="key"><h1>Popover</h1><section class="popover-matrix"><div class="popover-demo" @focusout="blur"><button ref="trigger" class="popover-trigger" aria-haspopup="dialog" :aria-expanded="shown" aria-controls="rich-popover" @click="toggle">{{label}}</button><div v-if="shown" id="rich-popover" ref="panel" tabindex="-1" role="dialog" :aria-label="label" :class="['kumo-popover','side-'+side,'align-'+align]" :style="{'--side-offset':sideOffset+'px','--align-offset':alignOffset+'px'}"><p>Popover content</p><button @click="shown=false;trigger?.focus()">Close</button></div></div></section></main></template>
